CREATE TABLE IF NOT EXISTS guild_config (guild_id INTEGER PRIMARY KEY, mod_log_channel_id INTEGER, automod_log_channel_id INTEGER, level_channel_id INTEGER, ticket_category_id INTEGER, ticket_log_channel_id INTEGER, suggestion_channel_id INTEGER, prefix TEXT, leveling_enabled INTEGER NOT NULL DEFAULT 1, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS command_usage_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER, user_id INTEGER NOT NULL, command TEXT NOT NULL, used_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS moderation_cases (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, case_number INTEGER NOT NULL, user_id INTEGER NOT NULL, moderator_id INTEGER NOT NULL, action TEXT NOT NULL, reason TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, UNIQUE(guild_id, case_number));
CREATE TABLE IF NOT EXISTS warnings (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, moderator_id INTEGER NOT NULL, reason TEXT NOT NULL, case_id INTEGER, active INTEGER NOT NULL DEFAULT 1, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS automod_config (guild_id INTEGER PRIMARY KEY, enabled INTEGER NOT NULL DEFAULT 0, spam_threshold INTEGER NOT NULL DEFAULT 5, mention_threshold INTEGER NOT NULL DEFAULT 8, invite_filter INTEGER NOT NULL DEFAULT 1, link_filter INTEGER NOT NULL DEFAULT 0, panic_mode INTEGER NOT NULL DEFAULT 0, log_channel_id INTEGER);
CREATE TABLE IF NOT EXISTS automod_violations (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, violation_type TEXT NOT NULL, content TEXT, action_taken TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS economy_users (guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, balance INTEGER NOT NULL DEFAULT 0, last_daily TEXT, last_work TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY(guild_id,user_id), CHECK(balance >= 0));
CREATE TABLE IF NOT EXISTS economy_transactions (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, amount INTEGER NOT NULL, reason TEXT NOT NULL, related_user_id INTEGER, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS shop_items (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, name TEXT NOT NULL, price INTEGER NOT NULL, description TEXT, UNIQUE(guild_id,name));
CREATE TABLE IF NOT EXISTS inventory_items (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, name TEXT NOT NULL, description TEXT, UNIQUE(guild_id,name));
CREATE TABLE IF NOT EXISTS user_inventory (guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, item_name TEXT NOT NULL, quantity INTEGER NOT NULL DEFAULT 1, PRIMARY KEY(guild_id,user_id,item_name));
CREATE TABLE IF NOT EXISTS leveling_users (guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, xp INTEGER NOT NULL DEFAULT 0, level INTEGER NOT NULL DEFAULT 0, last_xp_at REAL NOT NULL DEFAULT 0, PRIMARY KEY(guild_id,user_id));
CREATE TABLE IF NOT EXISTS level_rewards (guild_id INTEGER NOT NULL, level INTEGER NOT NULL, role_id INTEGER NOT NULL, PRIMARY KEY(guild_id,level));
CREATE TABLE IF NOT EXISTS tickets (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, channel_id INTEGER NOT NULL, status TEXT NOT NULL DEFAULT 'open', created_at TEXT DEFAULT CURRENT_TIMESTAMP, closed_at TEXT, closed_by INTEGER, close_reason TEXT);
CREATE TABLE IF NOT EXISTS ticket_logs (id INTEGER PRIMARY KEY AUTOINCREMENT, ticket_id INTEGER NOT NULL, action TEXT NOT NULL, actor_id INTEGER, note TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS starboard_config (guild_id INTEGER PRIMARY KEY, enabled INTEGER NOT NULL DEFAULT 0, channel_id INTEGER, threshold INTEGER NOT NULL DEFAULT 3, emoji TEXT NOT NULL DEFAULT '⭐', ignored_channels TEXT NOT NULL DEFAULT '');
CREATE TABLE IF NOT EXISTS starboard_messages (guild_id INTEGER NOT NULL, source_message_id INTEGER NOT NULL, starboard_message_id INTEGER, channel_id INTEGER NOT NULL, author_id INTEGER NOT NULL, star_count INTEGER NOT NULL DEFAULT 0, PRIMARY KEY(guild_id,source_message_id));
CREATE TABLE IF NOT EXISTS suggestions (id INTEGER PRIMARY KEY AUTOINCREMENT, guild_id INTEGER NOT NULL, user_id INTEGER NOT NULL, channel_id INTEGER, message_id INTEGER, text TEXT NOT NULL, status TEXT NOT NULL DEFAULT 'pending', reason TEXT, created_at TEXT DEFAULT CURRENT_TIMESTAMP, updated_at TEXT DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE IF NOT EXISTS suggestion_votes (suggestion_id INTEGER NOT NULL, user_id INTEGER NOT NULL, vote INTEGER NOT NULL, PRIMARY KEY(suggestion_id,user_id));
CREATE TABLE IF NOT EXISTS role_shop_items (guild_id INTEGER NOT NULL, role_id INTEGER NOT NULL, price INTEGER NOT NULL, PRIMARY KEY(guild_id,role_id));
